from dataclasses import dataclass, astuple
import enum
import unreal


class AnimationType(enum.Enum):
    PRP = 0
    BODY = 1
    HEAD = 2
    NULL = 999


@dataclass
class ImportParams:
    file_path: str = ""
    dst_path: str = ""
    skeleton_path: str = ""
    dst_name: str = ""
    animation_type: AnimationType = AnimationType.NULL
    bp: unreal.Blueprint = None
    skeletal_mesh: unreal.SkeletalMesh = None


@dataclass
class ImportResult:
    animation: unreal.AnimSequence = None
    skeletal_mesh: unreal.SkeletalMesh = None
    character_bp: unreal.Blueprint = None
    animation_type: AnimationType = AnimationType.NULL


@dataclass
class BodyHeadCombine:
    body: ImportResult = None
    head: ImportResult = None
    share_bp: unreal.Blueprint = None